const body = $input.first().json.body || $input.first().json;
const project_id = body.project_id;
if (!project_id) throw new Error('project_id required');
const force = body.force === true || body.force === 'true';
return [{ json: { project_id, force } }];

const body = $('Validate').first().json;
const project_id = body.project_id;
const force = body.force === true || body.force === 'true';

const topicsResult = $input.first().json;
const existingTopics = Array.isArray(topicsResult) ? topicsResult : [];
const existingCount = existingTopics.length;

const project = $('Read Project').first().json[0] || {};
const isCrashResume = force && project.status === 'generating_topics';

if (existingCount > 0 && !force) {
  return [{ json: { topics_exist: true, count: existingCount, project_id, __early_return: true } }];
}

let startTopicNumber, topicsNeeded;
if (isCrashResume && existingCount % 25 !== 0) {
  startTopicNumber = existingCount + 1;
  topicsNeeded = 25 - (existingCount % 25);
} else {
  startTopicNumber = existingCount + 1;
  topicsNeeded = 25;
}

const existingTitles = existingTopics.map(t => ({
  topic_number: t.topic_number,
  seo_title: t.seo_title,
  narrative_hook: t.narrative_hook
}));

return [{ json: { project_id, force, isCrashResume, existingCount, startTopicNumber, topicsNeeded, existingTitles, __early_return: false } }];

const project = $('Read Project').first().json[0] || $('Read Project').first().json;
const masterPrompt = $('Read Prompt Config').first().json[0]?.prompt_text || $('Read Prompt Config').first().json?.prompt_text;
const idempotency = $('Idempotency Guard').first().json;
const project_id = idempotency.project_id;
const topicsNeeded = idempotency.topicsNeeded || 25;
const existingTitles = idempotency.existingTitles || [];
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const hdr = { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK };

// CENTRAL INTELLIGENCE RENDERER v2 (migration 029)
// Now covers niche_profiles + yt_video_analyses + research_runs +
// research_categories + research_results + audience_insights in addition
// to projects/nvr/channel_analyses. The coverage check in migration 029
// makes it impossible to add a new column to any of those 9 tables without
// it landing in this rendered output.
let renderedIntelligence = '';
try {
  const intelRes = await fetch(SB + '/rest/v1/rpc/render_project_intelligence', {
    method: 'POST',
    headers: {
      apikey: $env.SUPABASE_ANON_KEY,
      Authorization: 'Bearer ' + SRK,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ p_project_id: project_id, p_stage: 'topics' })
  });
  if (intelRes.ok) renderedIntelligence = await intelRes.json();
} catch (_) {}

// === NVR INJECTION (added 2026-05-07) ===
// Replaces hardcoded `opportunity_scorecard:{verdict:'STRONG_GO',composite_score:8}` and
// `recommended_angle: project.niche_blue_ocean_strategy` with real viability data when present.
// The renderer markdown block already covers nvr - this keeps the structured JSON payload
// (Grand_Master_Prompt �2 contract) consistent with reality so Claude isn't told two
// different stories about the same niche. Falls back to legacy defaults if no nvr exists.
let _nvr = null;
try {
  if (project.analysis_group_id) {
    const _nvrRes = await fetch(
      SB + '/rest/v1/niche_viability_reports?analysis_group_id=eq.' + project.analysis_group_id + '&order=created_at.desc&limit=1',
      { headers: hdr }
    );
    if (_nvrRes.ok) {
      const _rows = await _nvrRes.json();
      _nvr = Array.isArray(_rows) && _rows[0] ? _rows[0] : null;
    }
  }
} catch (_) { /* leave _nvr=null, fall back to legacy defaults */ }
function _mapVerdict(v) {
  if (!v) return null;
  const s = String(v).toLowerCase();
  if (s === 'strong_opportunity') return 'STRONG_GO';
  if (s === 'moderate_opportunity') return 'GO';
  if (s === 'weak_opportunity') return 'MAYBE';
  if (s === 'avoid') return 'AVOID';
  return String(v).toUpperCase();
}
const _nvrVerdict = _mapVerdict(_nvr && _nvr.viability_verdict);
const _nvrScore10 = (_nvr && typeof _nvr.viability_score === 'number')
  ? Math.round(_nvr.viability_score / 10)
  : null;
const _nvrAngle = (_nvr && _nvr.recommended_angle) || null;
const _nvrBlueOcean = (_nvr && Array.isArray(_nvr.blue_ocean_opportunities) && _nvr.blue_ocean_opportunities.length > 0)
  ? _nvr.blue_ocean_opportunities
  : null;
// === END NVR INJECTION ===

// analysisPayload preserved: it serves Grand_Master_Prompt_Topic_Generator_v3 �2
// input contract (structured JSON payload). Primary source is project.competitive_analysis
// (cached from bridge workflow). niche_profiles fallback kept as a safety net -
// harmless duplication with the RPC's markdown rendering, but preserves the
// structural JSON contract the Grand Master prompt was written against.
const ca = project.competitive_analysis || {};
const analyses = ca.analyses || [];

let analysisPayload = '';
if (analyses.length > 0) {
  const _p1 = { primary_analysis: analyses[0], additional_analyses: analyses.slice(1), project_niche: project.niche, project_description: project.niche_description };
  if (_nvr) {
    _p1.opportunity_scorecard = { verdict: _nvrVerdict || 'STRONG_GO', composite_score: _nvrScore10 != null ? _nvrScore10 : 8 };
    _p1.ten_x_strategy = { recommended_angle: _nvrAngle || project.niche_blue_ocean_strategy || '' };
    if (_nvrBlueOcean) _p1.blue_ocean_analysis = { gaps_and_opportunities: _nvrBlueOcean };
  }
  analysisPayload = JSON.stringify(_p1, null, 2);
} else {
  try {
    const resp = await fetch(SB + '/rest/v1/niche_profiles?project_id=eq.' + project_id + '&order=created_at.desc&limit=1', { headers: hdr });
    const profiles = await resp.json();
    const profile = profiles && profiles[0];
    if (profile) {
      analysisPayload = JSON.stringify({
        niche_category: project.niche,
        project_niche: project.niche,
        project_description: project.niche_description || '',
        opportunity_scorecard: { verdict: _nvrVerdict || 'STRONG_GO', composite_score: _nvrScore10 != null ? _nvrScore10 : 8 },
        ten_x_strategy: { recommended_angle: _nvrAngle || project.niche_blue_ocean_strategy || '' },
        blue_ocean_analysis: { gaps_and_opportunities: _nvrBlueOcean || ((profile.blue_ocean_opportunities || {}).unoccupied_angles || []) },
        comment_insights: { top_questions: ((profile.audience_pain_points || {}).reddit || []).slice(0, 10), complaints: ((profile.audience_pain_points || {}).forums || []).slice(0, 5) }
      }, null, 2);
    }
  } catch (e) {}
  if (!analysisPayload) {
    const _p3 = {
      niche_category: project.niche,
      project_niche: project.niche,
      project_description: project.niche_description || '',
      opportunity_scorecard: { verdict: _nvrVerdict || 'STRONG_GO', composite_score: _nvrScore10 != null ? _nvrScore10 : 7 },
      ten_x_strategy: { recommended_angle: _nvrAngle || project.niche_blue_ocean_strategy || '' }
    };
    if (_nvrBlueOcean) _p3.blue_ocean_analysis = { gaps_and_opportunities: _nvrBlueOcean };
    analysisPayload = JSON.stringify(_p3, null, 2);
  }
}

// researchEnrichment DELETED per migration 029 - research_runs +
// research_categories + research_results are now fully rendered by the RPC
// with richer per-result metadata (subreddit, author, upvotes/comments/shares,
// AI-suggested titles) than the hand-built summary provided.

// === BEGIN AU OVERLAY (migration 034) - substitute country-slot placeholders
// Master prompts gained {country_compliance_block} / {country_terminology_block} /
// {country_calendar_context} / {country_demonetization_constraints} via 033 �K.
// render_country_blocks RPC returns the 4 sections per country_target
// (empty strings for GENERAL - substitution becomes a no-op). RPC failure
// leaves placeholders intact rather than silently stripping content.
let resolvedMaster = masterPrompt || '';
const __PLACEHOLDER_RE = /\{country_(?:compliance_block|terminology_block|calendar_context|demonetization_constraints)\}/;
if (resolvedMaster && __PLACEHOLDER_RE.test(resolvedMaster)) {
  try {
    const __blocksRes = await fetch(SB + '/rest/v1/rpc/render_country_blocks', {
      method: 'POST',
      headers: { apikey: $env.SUPABASE_ANON_KEY, Authorization: 'Bearer ' + SRK, 'Content-Type': 'application/json' },
      body: JSON.stringify({ p_country_target: await (async () => {
        try {
          const __ct_resp = await fetch(SB + '/rest/v1/projects?id=eq.' + project_id + '&select=country_target', { headers: hdr });
          if (__ct_resp.ok) {
            const __rows = await __ct_resp.json();
            if (Array.isArray(__rows) && __rows[0] && __rows[0].country_target) return __rows[0].country_target;
          }
        } catch(_) {}
        return (project.country_target || 'GENERAL');
      })() })
    });
    if (__blocksRes.ok) {
      const __b = await __blocksRes.json();
      resolvedMaster = resolvedMaster
        .replace(/\{country_compliance_block\}/g, (__b.country_compliance_block || ''))
        .replace(/\{country_terminology_block\}/g, (__b.country_terminology_block || ''))
        .replace(/\{country_calendar_context\}/g, (__b.country_calendar_context || ''))
        .replace(/\{country_demonetization_constraints\}/g, (__b.country_demonetization_constraints || ''));
    }
  } catch (_) { /* leave placeholders intact */ }
}
// === END AU OVERLAY ===

var prompt = renderedIntelligence ? renderedIntelligence + '\n\n---\n\n' : '';
prompt += resolvedMaster;
prompt += '\n\n=== RESEARCH ANALYSIS PAYLOAD ===\n' + analysisPayload;
if (existingTitles.length > 0) { prompt += '\n\nEXISTING TOPICS - avoid overlap:\n' + JSON.stringify(existingTitles); }

return [{ json: { project_id: project_id, niche: project.niche, prompt: prompt } }];

const response = $input.first().json;
if (response.error || response.type === 'error') {
  return [{ json: {
    isError: true,
    error_message: response.error?.message || JSON.stringify(response.error || response),
    project_id: $('Validate').first().json.project_id
  }}];
}
if (response.stop_reason === 'max_tokens') {
  return [{ json: {
    isError: true,
    error_message: 'Claude response truncated (stop_reason=max_tokens, output_tokens=' + (response.usage?.output_tokens || 'unknown') + '). Topics JSON incomplete.',
    project_id: $('Validate').first().json.project_id
  }}];
}
return [{ json: { ...response, isError: false } }];

const response = $input.first().json;
if (response.error) throw new Error('Anthropic error: ' + (response.error.message || JSON.stringify(response.error)));

const text = (response.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
let jsonText = text.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
const s = jsonText.indexOf('{'), e = jsonText.lastIndexOf('}');
if (s === -1 || e === -1) throw new Error('No JSON object in response');
const parsed = JSON.parse(jsonText.substring(s, e + 1));

const project_id = $('Validate').first().json.project_id;
// === BEGIN AU OVERLAY (migration 034 + 2026-04-28 fresh-fetch fix) - denormalize project.country_target onto each topic row
// Fetch country_target FRESH from DB at parse time. Previous code used $('Read Project').first().json[0]
// but n8n's HTTP Request node response shape made country_target unreachable in some cases - topics
// landed with the column DEFAULT ('GENERAL') even when the project was AU. Fresh fetch is bulletproof.
const __SB_URL = $env.SUPABASE_URL;
const __SB_SVC = $env.SUPABASE_SERVICE_ROLE_KEY;
let __country_target = 'GENERAL';
try {
  const __resp = await fetch(__SB_URL + '/rest/v1/projects?id=eq.' + project_id + '&select=country_target', {
    headers: { 'apikey': __SB_SVC, 'Authorization': 'Bearer ' + __SB_SVC }
  });
  if (__resp.ok) {
    const __rows = await __resp.json();
    if (Array.isArray(__rows) && __rows[0] && __rows[0].country_target) {
      __country_target = __rows[0].country_target;
    }
  }
} catch (__e) { /* keep GENERAL fallback */ }
// === END AU OVERLAY ===
const startTopicNumber = $('Idempotency Guard').first().json.startTopicNumber || 1;

const playlists = parsed.playlists || [];
const topicRows = [];
const avatarData = [];
const playlistMeta = [];

let globalTopicNum = startTopicNumber;

for (let pi = 0; pi < playlists.length; pi++) {
  const pl = playlists[pi];
  playlistMeta.push({ name: pl.playlist_title, theme: pl.playlist_theme });

  for (const t of (pl.topics || [])) {
    topicRows.push({
      project_id,
      topic_number: t.topic_number || globalTopicNum,
      playlist_group: pi + 1,
      playlist_angle: pl.playlist_title || '',
      original_title: t.subtopic || '',
      seo_title: t.subtopic || '',
      narrative_hook: t.primary_problem_trigger || '',
      key_segments: t.video_style_structure || '',
      estimated_cpm: null,
      viral_potential: null,
      core_domain_framework: t.core_domain_framework || '',
      primary_problem_trigger: t.primary_problem_trigger || '',
      target_audience_segment: t.target_audience_segment || '',
      psychographics: t.psychographics || '',
      key_emotional_drivers: t.key_emotional_drivers || '',
      video_style_structure: t.video_style_structure || '',
      content_angle_blue_ocean: t.content_angle_blue_ocean || '',
      viewer_search_intent: t.viewer_search_intent || '',
      practical_takeaways: t.practical_takeaways || '',
      country_target: __country_target,
      review_status: 'pending',
      status: 'pending'
    });

    avatarData.push({
      audience_avatar: t.audience_avatar || '',
      psychographics: t.psychographics || '',
      key_emotional_drivers: t.key_emotional_drivers || '',
      target_audience_segment: t.target_audience_segment || '',
      viewer_search_intent: t.viewer_search_intent || ''
    });

    globalTopicNum++;
  }
}

return [{ json: { project_id, topicRows, avatarData, playlistMeta } }];

// INSERT Topics returns 25 separate items - use $input.all()
const topics = $input.all().map(item => item.json);
const avatarData = $('Parse Topics').first().json.avatarData;
const topicRows = $('Parse Topics').first().json.topicRows;
const project_id = $('Validate').first().json.project_id;
const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const AK = $env.ANTHROPIC_API_KEY;

// Build avatar list text for Claude extraction
const avatarDescs = topics.map((t, i) => {
  const a = avatarData[i] || {};
  const tr = topicRows[i] || {};
  return `Avatar ${i+1}:\n- Name: ${(a.audience_avatar || '').substring(0, 100)}\n- Topic: ${t.seo_title || t.original_title}\n- Audience: ${a.target_audience_segment || ''}\n- Psycho: ${(a.psychographics || '').substring(0, 200)}\n- Pain: ${(tr.primary_problem_trigger || '').substring(0, 150)}`;
}).join('\n\n');

// Call Claude to extract 4 missing fields for all avatars in one batch
const prompt = `For each avatar below, extract/infer these 4 fields (1-2 sentences each):\n1. occupation_income - job/role and income bracket\n2. spending_profile - spending behavior relevant to topic\n3. knowledge_level - beginner/intermediate/advanced + brief note\n4. objection - #1 reason they would NOT act on this video\n\n${avatarDescs}\n\nReturn ONLY valid JSON array:\n[{"avatar_index":1,"occupation_income":"...","spending_profile":"...","knowledge_level":"...","objection":"..."}, ...]\nNo markdown. Valid JSON only.`;

let extracted = [];
try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {'Content-Type': 'application/json', 'x-api-key': AK, 'anthropic-version': '2023-06-01'},
    body: JSON.stringify({model: 'claude-sonnet-4-20250514', max_tokens: 16000, messages: [{role: 'user', content: prompt}]})
  });
  const d = await resp.json();
  const txt = (d.content || []).filter(c => c.type === 'text').map(c => c.text).join('');
  const clean = txt.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
  extracted = JSON.parse(clean.substring(clean.indexOf('['), clean.lastIndexOf(']') + 1));
} catch (e) {
  // Non-fatal - avatars will have partial data
}

// Build avatar rows with all fields
const avatarRows = topics.map((t, i) => {
  const a = avatarData[i] || {};
  const tr = topicRows[i] || {};
  const ext = extracted.find(e => e.avatar_index === i + 1) || {};
  const avatarText = a.audience_avatar || '';

  return {
    topic_id: t.id,
    project_id,
    video_title_short: t.seo_title || t.original_title,
    avatar_name_age: avatarText.split('.')[0]?.trim()?.substring(0, 100) || null,
    occupation_income: ext.occupation_income || null,
    life_stage: a.target_audience_segment || null,
    pain_point: tr.primary_problem_trigger || null,
    spending_profile: ext.spending_profile || null,
    knowledge_level: ext.knowledge_level || null,
    emotional_driver: a.key_emotional_drivers || null,
    online_hangouts: (a.viewer_search_intent || '').substring(0, 200) || null,
    objection: ext.objection || null,
    dream_outcome: (tr.practical_takeaways || '').substring(0, 200) || null,
    psychographics: a.psychographics || null,
    key_emotional_drivers: a.key_emotional_drivers || null,
    target_audience_segment: a.target_audience_segment || null,
    viewer_search_intent: a.viewer_search_intent || null,
    review_status: 'pending'
  };
});

// Update playlist metadata on project (non-fatal)
const playlistMeta = $('Parse Topics').first().json.playlistMeta || [];
const patch = {};
for (let i = 0; i < Math.min(playlistMeta.length, 5); i++) {
  patch['playlist' + (i+1) + '_name'] = playlistMeta[i].name || '';
  patch['playlist' + (i+1) + '_theme'] = playlistMeta[i].theme || '';
}
if (Object.keys(patch).length > 0) {
  try {
    await fetch(SB + '/rest/v1/projects?id=eq.' + project_id, {
      method: 'PATCH',
      headers: { 'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
      body: JSON.stringify(patch)
    });
  } catch (e) { /* non-fatal */ }
}

return [{ json: { project_id, avatarRows, topicsInserted: topics.length } }];

const project = $('Read Project').first().json[0] || $('Read Project').first().json;
const buildPrompt = $('Build Prompt').first().json;

const systemPrompt = 'You are a Senior Content Strategist and Niche Domain Researcher operating as the topic generation engine inside a YouTube content pipeline. Expertise: blue-ocean market strategy, deep niche authority positioning, YouTube algorithm mechanics, high-converting copywriting, audience psychographic profiling. Mandate: consume the research analysis, extract every exploitable signal, and engineer 25 video topics that occupy uncontested market space within the identified niche. CRITICAL OUTPUT CONTRACT: respond with EXACTLY ONE valid JSON object and nothing else. Start with the open brace and end with the close brace. No markdown, no code fences, no commentary, no explanatory headers. Follow the EXACT schema in the user message tail.';

const schemaExample = '{"playlists":[{"playlist_title":"","playlist_theme":"","topics":[{"topic_number":1,"subtopic":"","core_domain_framework":"","primary_problem_trigger":"","target_audience_segment":"","audience_avatar":"","psychographics":"","key_emotional_drivers":"","video_style_structure":"","content_angle_blue_ocean":"","viewer_search_intent":"","practical_takeaways":""}]}]}';

const tail = ' OUTPUT FORMAT (CRITICAL READ LAST): return EXACTLY ONE JSON object matching this exact schema (every key present, empty string for unknowns, NEVER omit a key): ' + schemaExample + ' . Total topics across all playlists: 25. Distribute across 3-5 playlists with thematic coherence per playlist. No markdown. No code fences. No prose. Start your response with the open brace and end with the close brace.';

const body = { model: 'claude-sonnet-4-20250514', max_tokens: 64000, system: systemPrompt, messages: [{ role: 'user', content: buildPrompt.prompt + tail }] };

return [{ json: { anthropicBody: JSON.stringify(body) } }];

// Dispatch register-analyze for each topic (fire-and-forget POST to local webhook)
// WF_REGISTER_ANALYZE responds immediately from Validate Request; Analyze & Write runs async in background.
const topics = $input.all().map(item => item.json);
const parseTopics = $('Parse Topics').first().json.topicRows || [];
const DASHBOARD_TOKEN = $env.DASHBOARD_API_TOKEN;
const WEBHOOK_BASE = $env.N8N_WEBHOOK_BASE || 'http://localhost:5678/webhook';

const promises = topics.map((t, i) => {
  const parsed = parseTopics[i] || {};
  const payload = {
    input_mode: 'topic',
    topic_id: t.id,
    topic_research_brief: [parsed.primary_problem_trigger, parsed.content_angle_blue_ocean, parsed.psychographics].filter(Boolean).join(' | '),
    topic_angle: parsed.playlist_angle || '',
    seo_title: t.seo_title || t.original_title || ''
  };
  return fetch(`${WEBHOOK_BASE}/register/analyze`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${DASHBOARD_TOKEN}`
    },
    body: JSON.stringify(payload)
  })
    .then(r => ({ topic_id: t.id, http: r.status }))
    .catch(e => ({ topic_id: t.id, error: e.message }));
});

try {
  const results = await Promise.race([
    Promise.all(promises),
    new Promise((res) => setTimeout(() => res([{ warning: 'dispatch-timeout-5s' }]), 5000))
  ]);
  console.log('Register analyze dispatch:', JSON.stringify(results).slice(0, 800));
} catch (e) {
  console.log('Register analyze dispatch error (non-fatal): ' + e.message);
}

// Pass INSERT Topics output through unchanged so Map Avatars sees the same 25 items
return $input.all();

// Dispatch WF_PREDICT_PERFORMANCE for each topic in this project.
// Runs AFTER WF_OUTLIER_SCORE + WF_SEO_SCORE; PPS depends on both outputs being persisted.
// Mirrors the 'Fire Register Analyze' pattern but waits for all completions
// (per-call AbortController timeout) since PPS has no respond-early pattern.

const projectId =
  ($('Validate').first()?.json?.project_id) ||
  ($('Idempotency Guard').first()?.json?.project_id) ||
  ($input.first()?.json?.project_id);

if (!projectId) {
  console.log('Fire PPS: no project_id resolvable upstream; skipping');
  return $input.all();
}

const DASHBOARD_TOKEN = $env.DASHBOARD_API_TOKEN;
const WEBHOOK_BASE = $env.N8N_WEBHOOK_BASE || 'http://localhost:5678/webhook';
const SUPABASE_URL = $env.SUPABASE_URL;

const sbHeaders = {
  apikey: $env.SUPABASE_ANON_KEY,
  Authorization: `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  Accept: 'application/json',
};

// Re-fetch topic IDs fresh (the upstream items may not have all 25 if Map Avatars filtered).
const topicsRes = await fetch(
  `${SUPABASE_URL}/rest/v1/topics?project_id=eq.${projectId}&select=id&order=topic_number.asc`,
  { method: 'GET', headers: sbHeaders }
);
if (!topicsRes.ok) {
  console.log(`Fire PPS: topic fetch HTTP ${topicsRes.status}`);
  return $input.all();
}
const topics = await topicsRes.json();
console.log(`Fire PPS: dispatching for ${topics.length} topics`);

async function callPps(topicId) {
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 60000); // 60s per-call ceiling
  try {
    const r = await fetch(`${WEBHOOK_BASE}/pps/calculate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${DASHBOARD_TOKEN}` },
      body: JSON.stringify({ topic_id: topicId, force: true }),
      signal: ctl.signal,
    });
    return { topic_id: topicId, http: r.status };
  } catch (e) {
    return { topic_id: topicId, error: e.name === 'AbortError' ? 'timeout-60s' : e.message };
  } finally {
    clearTimeout(t);
  }
}

const results = await Promise.all(topics.map(t => callPps(t.id)));
const ok = results.filter(r => r.http === 200).length;
const fail = results.length - ok;
console.log(`Fire PPS: ${ok} ok, ${fail} fail/timeout (sample: ${JSON.stringify(results.slice(0, 3))})`);

return $input.all();

const body = $input.first().json.body || $input.first().json;
const project_id = body.project_id;
if (!project_id) throw new Error('project_id required');
const force = body.force === true || body.force === 'true';
